export const Schema = z.object({
    世界: z.object({
        当前开局: z.coerce.number().transform(v => _.clamp(v, 0, 8)).default(0),
        当前日期: z.string().default(''),
        当前时间: z.string().default(''),
        当前日期时间: z.string().default(''),
        天数: z.coerce.number().transform(v => _.clamp(v, 0, 9999)).default(0),
        当前章节: z.coerce.number().transform(v => _.clamp(v, 1, 18)).default(1),
        章节名称: z.string().default(''),
        当前阶段: z.string().default('商朝末世'),
        当前事件: z.string().default(''),
        下一事件: z.string().default(''),
        当前区域: z.string().default(''),
        当前地点: z.string().default(''),
        天气氛围: z.string().default(''),
    }).prefault({}),
    玩家: z.object({
        身份信息: z.object({
            姓名: z.string().default(''),
            性别: z.string().default(''),
            年龄: z.string().default(''),
            出身: z.string().default(''),
            阵营: z.string().default('无阵营'),
            身份: z.string().default(''),
            门派: z.string().default('无门派'),
            救世动机: z.string().default(''),
            当前动向: z.string().default(''),
            过往经历: z.string().default(''),
        }).prefault({}),
        外貌: z.object({
            面部: z.string().default(''),
            体型: z.string().default(''),
            标志风格: z.string().default(''),
        }).prefault({}),
        修为: z.object({
            境界: z.string().default('凡人'),
            修为阶段描述: z.string().default(''),
            根行: z.coerce.number().transform(v => _.clamp(v, 0, 100)).default(0),
            杀劫沾染次数: z.coerce.number().transform(v => _.clamp(v, 0, 999)).default(0),
        }).prefault({}),
    }).prefault({}),
    状态: z.object({
        伤势: z.string().default('无'),
        生死状态: z.string().default('活'),
        是否战斗中: z.boolean().default(false),
    }).prefault({}),
    法宝: z.object({
        法宝库: z.record(z.string(), z.object({
            品质: z.string().default('普通'),
            类型: z.string().default(''),
            效果: z.string().default(''),
            出处: z.string().default(''),
            持有状态: z.string().default('持有'),
            当前祭出: z.boolean().default(false),
        }).prefault({})).default({}),
        当前祭出的法宝: z.string().default(''),
    }).prefault({}),
    因果: z.object({
        杀过的仙人: z.record(z.string(), z.object({
            同门: z.array(z.string()).default([]),
            已寻仇: z.boolean().default(false),
            寻仇者: z.string().default(''),
            死亡时间: z.string().default(''),
        }).prefault({})).default({}),
        仇人列表: z.record(z.string(), z.object({
            身份: z.string().default(''),
            寻仇原因: z.string().default(''),
            关系备注: z.string().default(''),
        }).prefault({})).default({}),
        盟友列表: z.record(z.string(), z.object({
            身份: z.string().default(''),
            结盟原因: z.string().default(''),
        }).prefault({})).default({}),
    }).prefault({}),
    势力关系: z.record(z.string(), z.coerce.number().transform(v => _.clamp(v, -100, 100))).default({}),
    人物好感度: z.record(z.string(), z.coerce.number().transform(v => _.clamp(v, 0, 100))).default({}),
    战斗: z.object({
        是否战斗中: z.boolean().default(false),
        对阵者: z.string().default(''),
        我方法宝: z.string().default(''),
        敌方法宝: z.string().default(''),
        阵法状态: z.string().default('无'),
        战斗阶段: z.string().default(''),
    }).prefault({}),
    NPC: z.object({
        关系列表: z.record(z.string(), z.object({
            好感: z.coerce.number().transform(v => _.clamp(v, 0, 100)).default(50),
            信赖: z.coerce.number().transform(v => _.clamp(v, 0, 100)).default(50),
            身份: z.string().default(''),
            关系备注: z.string().default(''),
            近期行为: z.string().default(''),
            心里话: z.string().default(''),
        }).prefault({})).default({}),
    }).prefault({}),
});
